void cpuinit(void) {
    for (struct cpu *it = cpus; &cpus[NCPU] > it; ++it)
        it->noff = 0, it->proc = 0, it->intena = 0;
#ifdef debug
    printf("cpuinit\n");
#endif
}

void procinit(void) {
    struct proc *p;

    initlock(&pid_lock, "nextpid");
    for (p = proc; &proc[NPROC] > p; ++p) {
        initlock(&p->lock, "proc");
        p->pid = 0;
        p->kstack = 0;
        p->sz = 0;
        p->pagetable = 0;
        p->kpagetable = 0;
        p->trapframe = 0;
        p->killed = 0;
        p->xstate = 0;
        p->state = UNUSED;
        p->parent = 0;
        p->chan = 0;
        for (int i = 0; NOFILE > i; ++i) p->ofile[i] = 0;
        p->cwd = 0;
        p->ext4_dir = 0;
        p->name[0] = 0;
        p->vma = 0;
        p->tmask = 0;
        p->ktime = 0;
        p->utime = 0;

        // signal
        memset(p->sigaction, 0, sizeof(p->sigaction));
        memset(p->sig_set.__val, 0, sizeof(p->sig_set));
        memset(p->sig_pending.__val, 0, sizeof(p->sig_pending));
        p->sig_tf = NULL;
    }
    memset(cpus, 0, sizeof(cpus));
#ifdef DEBUG
    printf("procinit\n");
#endif
}

int cpuid() {
    int idx = r_tp();
    return idx;
}

// Return this CPU's cpu struct.
// Interrupts must be disabled.
struct cpu *mycpu(void) {
    int idx = cpuid();
    struct cpu *c = &cpus[idx];
    return c;
}

// Return the current struct proc *, or zero if none.
struct proc *myproc(void) {
    push_off();
    struct cpu *c = mycpu();
    struct proc *p = c->proc;
    pop_off();
    return p;
}

int allocpid() {
    acquire(&pid_lock);
    int pid = nextpid;
    nextpid++;
    release(&pid_lock);
    return pid;
}

