/**
 * Physical memory allocator, for user processes,
 * kernel stacks, page-table pages,
 * and pipe buffers. Allocates whole 4096-byte pages.
 */

#include "sys/types.h"
#include "sys/param.h"
#include "mm/memlayout.h"
#include "sys/riscv.h"
#include "utils/spinlock.h"
#include "proc/kalloc.h"
#include "utils/string.h"
#include "utils/printf.h"

void freerange(void *pa_start, void *pa_end);

extern char kernel_end[];  // first address after kernel.

struct run {
    struct run *next;
};

struct {
    struct spinlock lock;
    struct run *freelist;
    uint64 npage;
} kmem;

/**
 * Initializes the physical memory allocator.
 * It initializes the lock, sets the number of pages to 0,
 * and sets the freelist to NULL.
 * It also calls the freerange function to free the memory
 * from kernel_end to PHYSTOP.
 */
void kinit() {
    initlock(&kmem.lock, "kmem");
    kmem.npage = 0;
    kmem.freelist = 0;
    freerange(kernel_end, (void *)PHYSTOP);
#ifdef DEBUG
    printf("kernel_end: %p, phystop: %p\nkinit\n", kernel_end, (void *)PHYSTOP);
#endif
}

/**
 * Frees a range of physical memory pages.
 *
 * @param pa_st The start address of the range (inclusive)
 * @param pa_ed The end address of the range (exclusive)
 */
void freerange(void *pa_st, void *pa_ed) {
    char *page_ptr;
    page_ptr = (char *)PGROUNDUP((uint64)pa_st);
    for (; (char *)pa_ed >= PGSIZE + page_ptr; page_ptr += PGSIZE)
        kfree(page_ptr);
}

/**
 * Frees a physical memory page previously allocated by kalloc.
 *
 * @param phys_addr The physical address of the memory page to be freed.
 */
void kfree(void *phys_addr) {
    struct run *r_ptr;

    if (kernel_end > (char *)phys_addr || PHYSTOP <= (uint64)phys_addr ||
        ((uint64)phys_addr % PGSIZE) != 0)
        panic("kfree");

    memset(phys_addr, 1, PGSIZE);
    r_ptr = (struct run *)phys_addr;
    acquire(&kmem.lock);
    r_ptr->next = kmem.freelist;
    kmem.freelist = r_ptr;
    ++kmem.npage;
    release(&kmem.lock);
}

/**
 * Allocates a physical memory page.
 *
 * @return A pointer to the allocated page, or NULL if no free pages are
 * available
 */
void *kalloc(void) {
    struct run *r_ptr;
    acquire(&kmem.lock);
    r_ptr = kmem.freelist;
    if (r_ptr != 0) {
        kmem.freelist = r_ptr->next;
        --kmem.npage;
    }
    release(&kmem.lock);
    if (r_ptr != 0) memset((char *)r_ptr, 5, PGSIZE);
    return (void *)r_ptr;
}

/**
 * Returns the amount of free memory in bytes.
 *
 * @return The amount of free memory in bytes
 */
uint64 freemem_amount(void) { return kmem.npage << PGSHIFT; }

void *kmalloc(uint64 size) {
    if (size == 0) {
        return NULL;
    }

    // 计算需要多少个页面
    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;
    void *addr = NULL;
    void *current_page;

    // 分配多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        current_page = kalloc();
        if (current_page == NULL) {
            // 分配失败，释放已经分配的页面
            for (uint64 j = 0; j < i; ++j) {
                kfree((char *)addr + j * PGSIZE);
            }
            return NULL;
        }
        if (i == 0) {
            addr = current_page;
        }
    }
    return addr;
}

void *cmalloc(uint64 cnt, uint each_size) {
    uint64 size = cnt * each_size;
    // printf("size is %d\n", size);
    if (size == 0) {
        return NULL;
    }

    // 计算需要多少个页面
    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;
    void *addr = NULL;
    void *current_page;

    // 分配多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        current_page = kalloc();
        memset(current_page, 0, PGSIZE);
        if (current_page == NULL) {
            // 分配失败，释放已经分配的页面
            for (uint64 j = 0; j < i; ++j) {
                kfree((char *)addr + j * PGSIZE);
            }
            return NULL;
        }
        if (i == 0) {
            addr = current_page;
        }
    }

    return addr;
}
void free(void *addr, uint64 size) {
    if (addr == NULL || size == 0) {
        return;
    }

    uint64 num_pages = (size + PGSIZE - 1) / PGSIZE;

    // 释放多个页面
    for (uint64 i = 0; i < num_pages; ++i) {
        kfree((char *)addr + i * PGSIZE);
    }
}

