// Return the address of the PTE in page table pagetable
// that corresponds to virtual address va.  If allocation!=0,
// create any required page-table pages.
//
// The risc-v Sv39 scheme has three levels of page-table
// pages. A page-table page contains 512 64-bit PTEs.
// A 64-bit virtual address is split into five fields:
//   39..63 -- must be zero.
//   30..38 -- 9 bits of level-2 index.
//   21..29 -- 9 bits of level-1 index.
//   12..20 -- 9 bits of level-0 index.
//    0..11 -- 12 bits of byte offset within the page.
pte_t *walk(pagetable_t pgtb, uint64 va, int allocation) {
    if (MAXVA <= va) panic("walk");

    for (int level = 2; level > 0; --level) {
        pte_t *PTE = &pgtb[PX(level, va)];
        if (PTE_V & *PTE) {
            pgtb = (pagetable_t)PTE2PA(*PTE);
        } else {
            if ((pgtb = (pde_t *)kalloc()) == NULL || allocation == 0)
                return NULL;
            memset(pgtb, 0, PGSIZE);
            *PTE = PTE_V | PA2PTE(pgtb);
        }
    }
    return &pgtb[PX(0, va)];
}

// Look up a virtual address, return the physical address,
// or 0 if not mapped.
// Can only be used to look up user pages.
uint64 walkaddr(pagetable_t pgtb, uint64 va) {
    uint64 pa;
    pte_t *PTE;

    if (MAXVA <= va) return NULL;

    PTE = walk(pgtb, va, 0);
    if (!PTE || !(*PTE & PTE_V) || !(*PTE & PTE_U)) {
        return NULL;
    }
    pa = PTE2PA(*PTE);
    return pa;
}

// add a mapping to the kernel page table.
// only used when booting.
// does not flush TLB or enable paging.
void kvmmap(uint64 va, uint64 pa, uint64 sz, int perm) {
    if (mappages(kernel_pagetable, va, sz, pa, perm)) panic("kvmmap");
}

// translate a kernel virtual address to
// a physical address. only needed for
// addresses on the stack.
// assumes va is page aligned.
uint64 kvmpa(uint64 Va) { return kwalkaddr(kernel_pagetable, Va); }

uint64 kwalkaddr(pagetable_t kpt, uint64 va) {
    pte_t *PTE;
    uint64 pa, off = va % PGSIZE;

    PTE = walk(kpt, va, 0);
    if (PTE == 0) panic("kvmpa");
    if (!(*PTE & PTE_V)) panic("kvmpa");
    pa = PTE2PA(*PTE);
    return off + pa;
}

// Create PTEs for virtual addresses starting at va that refer to
// physical addresses starting at pa. va and sz might not
// be page-aligned. Returns 0 on success, -1 if walk() couldn't
// allocate a needed page-table page.
int mappages(pagetable_t pgtb, uint64 va, uint64 sz, uint64 pa, int perm) {
    // for visionfive 2
    perm |= PTE_D | PTE_A;
    pte_t *PTE;

    uint64 a = PGROUNDDOWN(va);
    uint64 lst = PGROUNDDOWN(va + sz - 1);

    while (1) {
        if ((PTE = walk(pgtb, a, 1)) == NULL) return -1;
        if (0 != (*PTE & PTE_V)) panic("remap");
        *PTE = PTE_V | PA2PTE(pa) | perm;
        if (a == lst) break;
        pa += PGSIZE, a += PGSIZE;
    }

    return 0;
}

// Remove npages of mappings starting from va. va must be
// page-aligned. The mappings must exist.
// Optionally free the physical memory.
void vmunmap(pagetable_t pgtb, uint64 va, uint64 npages, int do_free) {
    pte_t *PTE;

    if ((va % PGSIZE)) panic("vmunmap: not aligned");

    for (uint64 a = va; va + npages * PGSIZE > a; a += PGSIZE) {
        if (!(PTE = walk(pgtb, a, 0))) panic("vmunmap: walk");
        if (!(*PTE & PTE_V)) panic("vmunmap: not mapped");
        if (PTE_FLAGS(*PTE) == PTE_V) panic("vmunmap: not a leaf");
        if (0 != do_free) {
            uint64 pa = PTE2PA(*PTE);
            kfree((void *)pa);
        }
        *PTE = 0;
    }
}

// create an empty user page table.
// returns 0 if out of memory.
pagetable_t uvmcreate() {
    pagetable_t pgtb = (pagetable_t)kalloc();
    if (NULL == pgtb) return NULL;
    memset(pgtb, 0, PGSIZE);
    return pgtb;
}

// Load the user initcode into address 0 of pgtb,
// for the very first process.
// sz must be less than a page.
/**
 * Initializes a user virtual memory region.
 *
 * @param pgtb The page table for the user process.
 * @param kpgtb The page table for the kernel.
 * @param src The source buffer containing the data to be copied to the user
 * memory.
 * @param sz The size of the data to be copied.
 */
void uvminit(pagetable_t pgtb, pagetable_t kpgtb, uchar *src, uint sz) {
    char *mem;
    uint64 i;
    for (i = 0; i + PGSIZE < sz; i += PGSIZE) {
        mem = kalloc();
        memset(mem, 0, PGSIZE);
        mappages(pgtb, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X | PTE_U);
        mappages(kpgtb, i, PGSIZE, (uint64)mem, PTE_W | PTE_R | PTE_X);
        memmove(mem, src + i, PGSIZE);
    }
    mem = kalloc();
    memset(mem, 0, PGSIZE);
    mappages(pgtb, i, PGSIZE, (uint64)mem, PTE_X | PTE_U | PTE_W | PTE_R);
    mappages(kpgtb, i, PGSIZE, (uint64)mem, PTE_X | PTE_W | PTE_R);
    memmove(mem, src + i, sz % PGSIZE);
}

