int fileexists(char *path) {
    uint64 ret = ext4_fexists(path);
    if (ret & EXT4_INODE_MODE_DIRECTORY) {
        return 4;  // dir
    } else if (ret & EXT4_INODE_MODE_FILE) {
        return 8;  // file
    } else {
        return ret / 4096;
    }
}
